#include<bits/stdc++.h>
using namespace std;
const int N = 4e5+20;
int n,m,ri,now,init,wz[N],tag[N];
int a[N],b[N][10],ans,id[N][10];
bool is[N],v[N];
string s;
int main(){
    cin>>n>>m;ri=m+10;
    for(int i=1;i<=n;i++){
        int x;cin>>x;
        is[x+ri]=1;
    }
    cin>>s;s=" "+s;
    for(int i=0;i<N;i++)id[i][9]=0x3f3f3f3f;//赋初值
    now=ri;
    for(int i=1;i<=m;i++){
        a[i]=a[i-1];//顺便求前缀和
        if(s[i]=='L')now--;//向左移
        else if(s[i]=='R')now++;//向右移
        else if(is[now]&&!v[now])v[now]=1,id[now][9]=i,a[i]++;
        //如果当前要开炮并且这个位置有靶子而且没被打过，统计答案并记录
        else;
        wz[i]=now;//存下当前位置
    }
    ans=a[m],init=now;//给最终答案赋上初始值并存下最后一个位置
    for(int k=-2;k<=2;k++){
        memset(v,0,sizeof(v));
        memset(tag,0,sizeof(tag));//多次使用变量，清空
        now=init+k;//一开始的位置（倒过来）
        for(int i=m;i>=1;i--){
            b[i][k+2]=b[i+1][k+2]+tag[i];//后缀和，加上之前留下的小标记
            if(s[i]=='L')now++;//反过来做
            else if(s[i]=='R')now--;//反过来做
            else if(is[now]){
                if(v[now])continue;//反过来都已经被打过了，不用考虑直接跳过
                v[now]=1,id[now][k+2]=i;//那么标记已经被打并且记录
                if(id[now][9]>=i)b[i][k+2]++;
                //如果当前位置已经比正着的首次打更早了，那么现在就可以加上答案
                else tag[id[now][9]]++;
                //否则给前面的数值打上小标记，等到那会儿再加上答案，现在先不能加
            }
            else;
        }
    }
    for(int i=1;i<=m;i++){
        int sum=0;
        if(s[i]=='L'){
            //把 L 换成 R
            sum=a[i-1]+b[i+1][4];
            ans=max(ans,sum);
            //把 L 换成 F
            sum=a[i-1]+b[i+1][3];
            if(is[wz[i-1]]&&(id[wz[i-1]][9]>i&&id[wz[i-1]][3]<i))sum++;
            //看看当前位置换成 F 了能不能多打一个靶子
            ans=max(ans,sum);
        }
        else if(s[i]=='R'){
            //把 R 换成 L
            sum=a[i-1]+b[i+1][0];
            ans=max(ans,sum);
            //把 R 换成 F
            sum=a[i-1]+b[i+1][1];
            if(is[wz[i-1]]&&(id[wz[i-1]][9]>i&&id[wz[i-1]][1]<i))sum++;
            //看看当前位置换成 F 了能不能多打一个靶子
            ans=max(ans,sum);
        }
        else{
            //把 F 换成 L
            sum=a[i-1]+b[i+1][1];
            ans=max(ans,sum);
            //把 F 换成 R
            sum=a[i-1]+b[i+1][3];
            ans=max(ans,sum);
        }
    }
    cout<<ans;
    return 0;
}
